// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Liveness probe
	// (GET /healthz)
	Healthz(w http.ResponseWriter, r *http.Request)
	// Readiness probe
	// (GET /readyz)
	Readyz(w http.ResponseWriter, r *http.Request)
	// List detector hits, optionally filtered by package / kind / time.
	// (GET /v1/anomalies)
	ListAnomalies(w http.ResponseWriter, r *http.Request, params ListAnomaliesParams)
	// Fetch a single anomaly by id.
	// (GET /v1/anomalies/{id})
	GetAnomaly(w http.ResponseWriter, r *http.Request, id int64)
	// Mint a short-lived JWT for internal / test use.
	// (POST /v1/auth/token)
	IssueAuthToken(w http.ResponseWriter, r *http.Request)
	// Given a list of IoCs, return affected components.
	// (POST /v1/blast-radius)
	BlastRadius(w http.ResponseWriter, r *http.Request)
	// List ingested components.
	// (GET /v1/components)
	ListComponents(w http.ResponseWriter, r *http.Request, params ListComponentsParams)
	// Upsert a component (idempotent).
	// (POST /v1/components)
	UpsertComponent(w http.ResponseWriter, r *http.Request)
	// List SBOMs for a component, oldest first.
	// (GET /v1/components/{componentRef}/sboms)
	ListSBOMsByComponent(w http.ResponseWriter, r *http.Request, componentRef ComponentRef)
	// Submit a new SBOM for a component.
	// (POST /v1/components/{componentRef}/sboms)
	SubmitSBOM(w http.ResponseWriter, r *http.Request, componentRef ComponentRef)
	// List incidents, filterable across multiple dimensions.
	// (GET /v1/incidents)
	ListIncidents(w http.ResponseWriter, r *http.Request, params ListIncidentsParams)
	// Get an incident by id.
	// (GET /v1/incidents/{id})
	GetIncident(w http.ResponseWriter, r *http.Request, id string)
	// Joined incident view (incident + IoC + affected components + remediations).
	// (GET /v1/incidents/{id}/detail)
	GetIncidentDetail(w http.ResponseWriter, r *http.Request, id string)
	// Record a remediation action on an incident (audit-only).
	// (POST /v1/incidents/{id}/remediations)
	AddRemediation(w http.ResponseWriter, r *http.Request, id string)
	// Transition an incident's state.
	// (POST /v1/incidents/{id}/transition)
	TransitionIncident(w http.ResponseWriter, r *http.Request, id string)
	// List known IoCs.
	// (GET /v1/iocs)
	ListIoCs(w http.ResponseWriter, r *http.Request, params ListIoCsParams)
	// Submit an IoC (from a feed or manual entry).
	// (POST /v1/iocs)
	SubmitIoC(w http.ResponseWriter, r *http.Request)
	// Newest-first list of publisher snapshots for a package.
	// (GET /v1/publisher/{packageRef}/history)
	GetPublisherHistory(w http.ResponseWriter, r *http.Request, packageRef string, params GetPublisherHistoryParams)
	// Get a specific SBOM by id.
	// (GET /v1/sboms/{id})
	GetSBOM(w http.ResponseWriter, r *http.Request, id string)
	// Server-sent-events stream of live domain events.
	// (GET /v1/stream)
	Stream(w http.ResponseWriter, r *http.Request, params StreamParams)
}

